  1	//! This state node is used for expansions.
  2	//!
  3	//! If a word contains command substitution or glob expansion syntax then it
  4	//! needs to do IO, so we have to keep track of the state for that.
  5	//!
  6	//! TODO PERF: in the case of expanding cmd args, we probably want to use the spawn args arena
  7	//! otherwise the interpreter allocator
  8	pub const Expansion = @This();
  9	
 10	base: State,
 11	node: *const ast.Atom,
 12	parent: ParentPtr,
 13	io: IO,
 14	
 15	word_idx: u32,
 16	current_out: std.array_list.Managed(u8),
 17	state: union(enum) {
 18	    normal,
 19	    braces,
 20	    glob,
 21	    done,
 22	    err: bun.shell.ShellErr,
 23	},
 24	child_state: union(enum) {
 25	    idle,
 26	    cmd_subst: struct {
 27	        cmd: *Script,
 28	        quoted: bool = false,
 29	    },
 30	    // TODO
 31	    glob: struct {
 32	        initialized: bool = false,
 33	        walker: GlobWalker,
 34	    },
 35	},
 36	out_exit_code: ExitCode = 0,
 37	out: Result,
 38	out_idx: u32,
 39	/// Set when the word contains a quoted_empty atom, indicating that an empty
 40	/// result should still be preserved as an argument (POSIX: `""` produces an empty arg).
 41	has_quoted_empty: bool = false,
 42	
 43	pub const ParentPtr = StatePtrUnion(.{
 44	    Cmd,
 45	    Assigns,
 46	    CondExpr,
 47	    Subshell,
 48	});
 49	
 50	pub const ChildPtr = StatePtrUnion(.{
 51	    // Cmd,
 52	    Script,
 53	});
 54	
 55	pub const Result = union(enum) {
 56	    array_of_slice: *std.array_list.Managed([:0]const u8),
 57	    array_of_ptr: *std.array_list.Managed(?[*:0]const u8),
 58	    single: struct {
 59	        list: *std.array_list.Managed(u8),
 60	        done: bool = false,
 61	    },
 62	
 63	    const PushAction = enum {
 64	        /// We just copied the buf into the result, caller can just do
 65	        /// `.clearRetainingCapacity()`
 66	        copied,
 67	        /// We took ownershipo of the result and placed the pointer in the buf,
 68	        /// caller should remove any references to the underlying data.
 69	        moved,
 70	    };
 71	
 72	    pub fn pushResultSliceOwned(this: *Result, buf: [:0]const u8) PushAction {
 73	        if (comptime bun.Environment.allow_assert) {
 74	            assert(buf[buf.len] == 0);
 75	        }
 76	
 77	        switch (this.*) {
 78	            .array_of_slice => {
 79	                bun.handleOom(this.array_of_slice.append(buf));
 80	                return .moved;
 81	            },
 82	            .array_of_ptr => {
 83	                bun.handleOom(this.array_of_ptr.append(@as([*:0]const u8, @ptrCast(buf.ptr))));
 84	                return .moved;
 85	            },
 86	            .single => {
 87	                if (this.single.done) return .copied;
 88	                bun.handleOom(this.single.list.appendSlice(buf[0 .. buf.len + 1]));
 89	                this.single.done = true;
 90	                return .copied;
 91	            },
 92	        }
 93	    }
 94	
 95	    pub fn pushResult(this: *Result, buf: *std.array_list.Managed(u8)) PushAction {
 96	        if (comptime bun.Environment.allow_assert) {
 97	            assert(buf.items[buf.items.len - 1] == 0);
 98	        }
 99	
100	        switch (this.*) {
101	            .array_of_slice => {
102	                bun.handleOom(this.array_of_slice.append(buf.items[0 .. buf.items.len - 1 :0]));
103	                return .moved;
104	            },
105	            .array_of_ptr => {
106	                bun.handleOom(this.array_of_ptr.append(@as([*:0]const u8, @ptrCast(buf.items.ptr))));
107	                return .moved;
108	            },
109	            .single => {
110	                if (this.single.done) return .copied;
111	                bun.handleOom(this.single.list.appendSlice(buf.items[0..]));
112	                return .copied;
113	            },
114	        }
115	    }
116	};
