126	pub fn init(
127	    interpreter: *Interpreter,
128	    shell_state: *ShellExecEnv,
129	    expansion: *Expansion,
130	    node: *const ast.Atom,
131	    parent: ParentPtr,
132	    out_result: Result,
133	    io: IO,
134	) void {
135	    log("Expansion(0x{x}) init", .{@intFromPtr(expansion)});
136	    expansion.* = .{
137	        .node = node,
138	        .base = State.initBorrowedAllocScope(.expansion, interpreter, shell_state, parent.scopedAllocator()),
139	        .parent = parent,
140	
141	        .word_idx = 0,
142	        .state = .normal,
143	        .child_state = .idle,
144	        .out = out_result,
145	        .out_idx = 0,
146	        .current_out = undefined,
147	        .io = io,
148	    };
149	    expansion.current_out = std.array_list.Managed(u8).init(expansion.base.allocator());
150	}
