152	pub fn deinit(expansion: *Expansion) void {
153	    log("Expansion(0x{x}) deinit", .{@intFromPtr(expansion)});
154	    expansion.current_out.deinit();
155	    expansion.io.deinit();
156	    expansion.base.endScope();
157	}
