159	pub fn start(this: *Expansion) Yield {
160	    if (comptime bun.Environment.allow_assert) {
161	        assert(this.child_state == .idle);
162	        assert(this.word_idx == 0);
163	    }
164	
165	    this.state = .normal;
166	    return .{ .expansion = this };
167	}
