169	pub fn next(this: *Expansion) Yield {
170	    while (!(this.state == .done or this.state == .err)) {
171	        switch (this.state) {
172	            .normal => {
173	                // initialize
174	                if (this.word_idx == 0) {
175	                    var has_unknown = false;
176	                    // + 1 for sentinel
177	                    const string_size = this.expansionSizeHint(this.node, &has_unknown);
178	                    bun.handleOom(this.current_out.ensureUnusedCapacity(string_size + 1));
179	                }
180	
181	                while (this.word_idx < this.node.atomsLen()) {
182	                    if (this.expandVarAndCmdSubst(this.word_idx)) |yield| return yield;
183	                }
184	
185	                if (this.word_idx >= this.node.atomsLen()) {
186	                    if (this.node.hasTildeExpansion() and this.node.atomsLen() > 1) {
187	                        const homedir = this.base.shell.getHomedir();
188	                        defer homedir.deref();
189	                        if (this.current_out.items.len > 0) {
190	                            switch (this.current_out.items[0]) {
191	                                '/', '\\' => {
192	                                    bun.handleOom(this.current_out.insertSlice(0, homedir.slice()));
193	                                },
194	                                else => {
195	                                    // TODO: Handle username
196	                                    bun.handleOom(this.current_out.insert(0, '~'));
197	                                },
198	                            }
199	                        } else if (this.has_quoted_empty) {
200	                            // ~"" or ~'' should expand to the home directory
201	                            bun.handleOom(this.current_out.appendSlice(homedir.slice()));
202	                        }
203	                    }
204	
205	                    // NOTE brace expansion + cmd subst has weird behaviour we don't support yet, ex:
206	                    // echo $(echo a b c){1,2,3}
207	                    // >> a b c1 a b c2 a b c3
208	                    if (this.node.has_brace_expansion()) {
209	                        this.state = .braces;
210	                        continue;
211	                    }
212	
213	                    if (this.node.has_glob_expansion()) {
214	                        this.state = .glob;
215	                        continue;
216	                    }
217	
218	                    this.pushCurrentOut();
219	                    this.state = .done;
220	                    continue;
221	                }
222	
223	                // Shouldn't fall through to here
224	                assert(this.word_idx >= this.node.atomsLen());
225	                return .suspended;
226	            },
227	            .braces => {
228	                var arena = Arena.init(this.base.allocator());
229	                defer arena.deinit();
230	                const arena_allocator = arena.allocator();
231	                const brace_str = this.current_out.items[0..];
232	                var lexer_output = if (bun.strings.isAllASCII(brace_str)) lexer_output: {
233	                    @branchHint(.likely);
234	                    break :lexer_output bun.handleOom(Braces.Lexer.tokenize(arena_allocator, brace_str));
235	                } else lexer_output: {
236	                    break :lexer_output bun.handleOom(Braces.NewLexer(.wtf8).tokenize(arena_allocator, brace_str));
237	                };
238	                const expansion_count = Braces.calculateExpandedAmount(lexer_output.tokens.items[0..]);
239	
240	                const stack_max = comptime 16;
241	                comptime {
242	                    assert(@sizeOf([]std.array_list.Managed(u8)) * stack_max <= 256);
243	                }
244	                var maybe_stack_alloc = std.heap.stackFallback(@sizeOf([]std.array_list.Managed(u8)) * stack_max, arena_allocator);
245	                const stack_alloc = maybe_stack_alloc.get();
246	                const expanded_strings = bun.handleOom(stack_alloc.alloc(std.array_list.Managed(u8), expansion_count));
247	
248	                for (0..expansion_count) |i| {
249	                    expanded_strings[i] = std.array_list.Managed(u8).init(this.base.allocator());
250	                }
251	
252	                Braces.expand(
253	                    arena_allocator,
254	                    lexer_output.tokens.items[0..],
255	                    expanded_strings,
256	                    lexer_output.contains_nested,
257	                ) catch |err| switch (err) {
258	                    error.OutOfMemory => bun.outOfMemory(),
259	                    error.UnexpectedToken => std.debug.panic(
260	                        "unexpected error from Braces.expand: UnexpectedToken",
261	                        .{},
262	                    ),
263	                };
264	
265	                this.outEnsureUnusedCapacity(expansion_count);
266	
267	                // Add sentinel values
268	                for (0..expansion_count) |i| {
269	                    bun.handleOom(expanded_strings[i].append(0));
270	                    switch (this.out.pushResult(&expanded_strings[i])) {
271	                        .copied => {
272	                            expanded_strings[i].deinit();
273	                        },
274	                        .moved => {
275	                            expanded_strings[i].clearRetainingCapacity();
276	                        },
277	                    }
278	                }
279	
280	                if (this.node.has_glob_expansion()) {
281	                    this.state = .glob;
282	                } else {
283	                    this.state = .done;
284	                }
285	            },
286	            .glob => {
287	                return this.transitionToGlobState();
288	            },
289	            .done, .err => unreachable,
290	        }
291	    }
292	
293	    if (this.state == .done) {
294	        return this.parent.childDone(this, 0);
295	    }
296	
297	    // Parent will inspect the `this.state.err`
298	    if (this.state == .err) {
299	        return this.parent.childDone(this, 1);
300	    }
301	
302	    unreachable;
303	}
