305	fn transitionToGlobState(this: *Expansion) Yield {
306	    var arena = Arena.init(this.base.allocator());
307	    this.child_state = .{ .glob = .{ .walker = .{} } };
308	    const pattern = this.current_out.items[0..];
309	
310	    const cwd = this.base.shell.cwd();
311	
312	    switch (GlobWalker.initWithCwd(
313	        &this.child_state.glob.walker,
314	        &arena,
315	        pattern,
316	        cwd,
317	        false,
318	        false,
319	        false,
320	        false,
321	        false,
322	    ) catch |err| bun.handleOom(err)) {
323	        .result => {},
324	        .err => |e| {
325	            arena.deinit();
326	            this.child_state = .idle;
327	            this.state = .{ .err = bun.shell.ShellErr.newSys(e) };
328	            return .{ .expansion = this };
329	        },
330	    }
331	
332	    var task = ShellGlobTask.createOnMainThread(&this.child_state.glob.walker, this);
333	    task.schedule();
334	    return .suspended;
335	}
