337	pub fn expandVarAndCmdSubst(this: *Expansion, start_word_idx: u32) ?Yield {
338	    switch (this.node.*) {
339	        .simple => |*simp| {
340	            const is_cmd_subst = this.expandSimpleNoIO(simp, &this.current_out, true);
341	            if (is_cmd_subst) {
342	                var io: IO = .{
343	                    .stdin = this.base.rootIO().stdin.ref(),
344	                    .stdout = .pipe,
345	                    .stderr = this.base.rootIO().stderr.ref(),
346	                };
347	                const shell_state = switch (this.base.shell.dupeForSubshell(this.base.allocScope(), this.base.allocator(), io, .cmd_subst)) {
348	                    .result => |s| s,
349	                    .err => |e| {
350	                        io.deref();
351	                        this.base.throw(&bun.shell.ShellErr.newSys(e));
352	                        return .failed;
353	                    },
354	                };
355	                var script = Script.init(this.base.interpreter, shell_state, &this.node.simple.cmd_subst.script, Script.ParentPtr.init(this), io);
356	                this.child_state = .{
357	                    .cmd_subst = .{
358	                        .cmd = script,
359	                        .quoted = simp.cmd_subst.quoted,
360	                    },
361	                };
362	                return script.start();
363	            } else {
364	                this.word_idx += 1;
365	            }
366	        },
367	        .compound => |cmp| {
368	            // The tilde is always the first atom of the compound word. Skip it only on the
369	            // initial pass (start_word_idx == 0); when we re-enter after a command
370	            // substitution completes, `start_word_idx` already points at the next atom to
371	            // process and applying the offset again would skip it.
372	            const starting_offset: usize = if (start_word_idx == 0 and this.node.hasTildeExpansion()) brk: {
373	                this.word_idx += 1;
374	                break :brk 1;
375	            } else 0;
376	            for (cmp.atoms[start_word_idx + starting_offset ..]) |*simple_atom| {
377	                const is_cmd_subst = this.expandSimpleNoIO(simple_atom, &this.current_out, true);
378	                if (is_cmd_subst) {
379	                    var io: IO = .{
380	                        .stdin = this.base.rootIO().stdin.ref(),
381	                        .stdout = .pipe,
382	                        .stderr = this.base.rootIO().stderr.ref(),
383	                    };
384	                    const shell_state = switch (this.base.shell.dupeForSubshell(this.base.allocScope(), this.base.allocator(), io, .cmd_subst)) {
385	                        .result => |s| s,
386	                        .err => |e| {
387	                            io.deref();
388	                            this.base.throw(&bun.shell.ShellErr.newSys(e));
389	                            return .failed;
390	                        },
391	                    };
392	                    var script = Script.init(this.base.interpreter, shell_state, &simple_atom.cmd_subst.script, Script.ParentPtr.init(this), io);
393	                    this.child_state = .{
394	                        .cmd_subst = .{
395	                            .cmd = script,
396	                            .quoted = simple_atom.cmd_subst.quoted,
397	                        },
398	                    };
399	                    return script.start();
400	                } else {
401	                    this.word_idx += 1;
402	                    this.child_state = .idle;
403	                }
404	            }
405	        },
406	    }
407	
408	    return null;
409	}
