411	/// Remove a set of values from the beginning and end of a slice.
412	pub fn trim(slice: []u8, values_to_strip: []const u8) []u8 {
413	    var begin: usize = 0;
414	    var end: usize = slice.len;
415	    while (begin < end and std.mem.indexOfScalar(u8, values_to_strip, slice[begin]) != null) : (begin += 1) {}
416	    while (end > begin and std.mem.indexOfScalar(u8, values_to_strip, slice[end - 1]) != null) : (end -= 1) {}
417	    return slice[begin..end];
418	}
