420	/// 1. Turn all newlines into spaces
421	/// 2. Strip last newline if it exists
422	/// 3. Trim leading, trailing, and consecutive whitespace
423	fn postSubshellExpansion(this: *Expansion, stdout_: []u8) void {
424	    // 1. and 2.
425	    var stdout = convertNewlinesToSpaces(stdout_);
426	
427	    // Trim leading & trailing whitespace
428	    stdout = trim(stdout, " \n  \r\t");
429	    if (stdout.len == 0) return;
430	
431	    // Trim consecutive
432	    var prev_whitespace: bool = false;
433	    var a: usize = 0;
434	    var b: usize = 1;
435	    for (stdout[0..], 0..) |c, i| {
436	        if (prev_whitespace) {
437	            if (c != ' ') {
438	                a = i;
439	                b = i + 1;
440	                prev_whitespace = false;
441	            }
442	            continue;
443	        }
444	
445	        b = i + 1;
446	        if (c == ' ') {
447	            b = i;
448	            prev_whitespace = true;
449	            bun.handleOom(this.current_out.appendSlice(stdout[a..b]));
450	            this.pushCurrentOut();
451	        }
452	    }
453	    // "aa bbb"
454	
455	    bun.handleOom(this.current_out.appendSlice(stdout[a..b]));
456	}
