458	fn convertNewlinesToSpaces(stdout_: []u8) []u8 {
459	    var stdout = brk: {
460	        if (stdout_.len == 0) return stdout_;
461	        if (stdout_[stdout_.len -| 1] == '\n') break :brk stdout_[0..stdout_.len -| 1];
462	        break :brk stdout_[0..];
463	    };
464	
465	    if (stdout.len == 0) {
466	        return stdout;
467	    }
468	
469	    // From benchmarks the SIMD stuff only is faster when chars >= 64
470	    if (stdout.len < 64) {
471	        convertNewlinesToSpacesSlow(0, stdout);
472	        return stdout[0..];
473	    }
474	
475	    const needles: @Vector(16, u8) = @splat('\n');
476	    const spaces: @Vector(16, u8) = @splat(' ');
477	    var i: usize = 0;
478	    while (i + 16 <= stdout.len) : (i += 16) {
479	        const haystack: @Vector(16, u8) = stdout[i..][0..16].*;
480	        stdout[i..][0..16].* = @select(u8, haystack == needles, spaces, haystack);
481	    }
482	
483	    if (i < stdout.len) convertNewlinesToSpacesSlow(i, stdout);
484	    return stdout[0..];
485	}
486	
487	fn convertNewlinesToSpacesSlow(i: usize, stdout: []u8) void {
488	    for (stdout[i..], i..) |c, j| {
489	        if (c == '\n') {
490	            stdout[j] = ' ';
491	        }
492	    }
493	}
