495	pub fn childDone(this: *Expansion, child: ChildPtr, exit_code: ExitCode) Yield {
496	    if (comptime bun.Environment.allow_assert) {
497	        assert(this.state != .done and this.state != .err);
498	        assert(this.child_state != .idle);
499	    }
500	
501	    // Command substitution
502	    if (child.ptr.is(Script)) {
503	        if (comptime bun.Environment.allow_assert) {
504	            assert(this.child_state == .cmd_subst);
505	        }
506	
507	        // This branch is true means that we expanded
508	        // a single command substitution and it failed.
509	        //
510	        // This information is propagated to `Cmd` because in the case
511	        // that the command substitution would be expanded to the
512	        // command name (e.g. `$(lkdfjsldf)`), and it fails, the entire
513	        // command should fail with the exit code of the command
514	        // substitution.
515	        if (exit_code != 0 and
516	            this.node.* == .simple and
517	            this.node.simple == .cmd_subst)
518	        {
519	            this.out_exit_code = exit_code;
520	        }
521	
522	        const stdout = this.child_state.cmd_subst.cmd.base.shell.buffered_stdout().slice();
523	        if (!this.child_state.cmd_subst.quoted) {
524	            this.postSubshellExpansion(stdout);
525	        } else {
526	            const trimmed = std.mem.trimRight(u8, stdout, " \n\t\r");
527	            bun.handleOom(this.current_out.appendSlice(trimmed));
528	        }
529	
530	        this.word_idx += 1;
531	        this.child_state = .idle;
532	        child.deinit();
533	        return .{ .expansion = this };
534	    }
535	
536	    @panic("Invalid child to Expansion, this indicates a bug in Bun. Please file a report on Github.");
537	}
