539	fn onGlobWalkDone(this: *Expansion, task: *ShellGlobTask) Yield {
540	    log("{f} onGlobWalkDone", .{this});
541	    if (comptime bun.Environment.allow_assert) {
542	        assert(this.child_state == .glob);
543	    }
544	
545	    if (task.err) |*err| {
546	        switch (err.*) {
547	            .syscall => {
548	                this.base.throw(&bun.shell.ShellErr.newSys(task.err.?.syscall));
549	            },
550	            .unknown => |errtag| {
551	                this.base.throw(&.{
552	                    .custom = bun.handleOom(this.base.allocator().dupe(u8, @errorName(errtag))),
553	                });
554	            },
555	        }
556	    }
557	
558	    if (task.result.items.len == 0) {
559	        // In variable assignments, a glob that fails to match should not produce an error, but instead expand to just the pattern
560	        if (this.parent.ptr.is(Assigns) or (this.parent.ptr.is(Cmd) and this.parent.ptr.as(Cmd).state == .expanding_assigns)) {
561	            this.pushCurrentOut();
562	            this.child_state.glob.walker.deinit(true);
563	            this.child_state = .idle;
564	            this.state = .done;
565	            return .{ .expansion = this };
566	        }
567	
568	        const msg = bun.handleOom(std.fmt.allocPrint(this.base.allocator(), "no matches found: {s}", .{this.child_state.glob.walker.pattern}));
569	        this.state = .{
570	            .err = bun.shell.ShellErr{
571	                .custom = msg,
572	            },
573	        };
574	        this.child_state.glob.walker.deinit(true);
575	        this.child_state = .idle;
576	        return .{ .expansion = this };
577	    }
578	
579	    for (task.result.items) |sentinel_str| {
580	        // The string is allocated in the glob walker arena and will be freed, so needs to be duped here
581	        const duped = bun.handleOom(this.base.allocator().dupeZ(u8, sentinel_str[0..sentinel_str.len]));
582	        switch (this.out.pushResultSliceOwned(duped)) {
583	            .copied => {
584	                this.base.allocator().free(duped);
585	            },
586	            .moved => {},
587	        }
588	    }
589	
590	    this.word_idx += 1;
591	    this.child_state.glob.walker.deinit(true);
592	    this.child_state = .idle;
593	    this.state = .done;
594	    return .{ .expansion = this };
595	}
