597	/// If the atom is actually a command substitution then does nothing and returns true
598	pub fn expandSimpleNoIO(this: *Expansion, atom: *const ast.SimpleAtom, str_list: *std.array_list.Managed(u8), comptime expand_tilde: bool) bool {
599	    switch (atom.*) {
600	        .Text => |txt| {
601	            bun.handleOom(str_list.appendSlice(txt));
602	        },
603	        .quoted_empty => {
604	            // A quoted empty string ("", '', or ${''}). We must ensure the word
605	            // is not dropped by pushCurrentOut, so mark it with a flag.
606	            this.has_quoted_empty = true;
607	        },
608	        .Var => |label| {
609	            bun.handleOom(str_list.appendSlice(this.expandVar(label)));
610	        },
611	        .VarArgv => |int| {
612	            bun.handleOom(str_list.appendSlice(this.expandVarArgv(int)));
613	        },
614	        .asterisk => {
615	            bun.handleOom(str_list.append('*'));
616	        },
617	        .double_asterisk => {
618	            bun.handleOom(str_list.appendSlice("**"));
619	        },
620	        .brace_begin => {
621	            bun.handleOom(str_list.append('{'));
622	        },
623	        .brace_end => {
624	            bun.handleOom(str_list.append('}'));
625	        },
626	        .comma => {
627	            bun.handleOom(str_list.append(','));
628	        },
629	        .tilde => {
630	            if (expand_tilde) {
631	                const homedir = this.base.shell.getHomedir();
632	                defer homedir.deref();
633	                bun.handleOom(str_list.appendSlice(homedir.slice()));
634	            } else bun.handleOom(str_list.append('~'));
635	        },
636	        .cmd_subst => {
637	            // TODO:
638	            // if the command substution is comprised of solely shell variable assignments then it should do nothing
639	            // if (atom.cmd_subst.* == .assigns) return false;
640	            return true;
641	        },
642	    }
643	    return false;
644	}
