651	pub fn pushCurrentOut(this: *Expansion) void {
652	    if (this.current_out.items.len == 0 and !this.has_quoted_empty) return;
653	    if (this.current_out.items.len == 0 or this.current_out.items[this.current_out.items.len - 1] != 0) bun.handleOom(this.current_out.append(0));
654	    switch (this.out.pushResult(&this.current_out)) {
655	        .copied => {
656	            this.current_out.clearRetainingCapacity();
657	        },
658	        .moved => {
659	            this.current_out = std.array_list.Managed(u8).init(this.base.allocator());
660	        },
661	    }
662	}
