664	fn expandVar(this: *const Expansion, label: []const u8) []const u8 {
665	    const value = this.base.shell.shell_env.get(EnvStr.initSlice(label)) orelse brk: {
666	        break :brk this.base.shell.export_env.get(EnvStr.initSlice(label)) orelse return "";
667	    };
668	    defer value.deref();
669	    return value.slice();
670	}
