672	fn expandVarArgv(this: *const Expansion, original_int: u8) []const u8 {
673	    var int = original_int;
674	    switch (this.base.interpreter.event_loop) {
675	        .js => |event_loop| {
676	            if (int == 0) return bun.selfExePath() catch "";
677	            int -= 1;
678	
679	            const vm = event_loop.virtual_machine;
680	            if (vm.main.len > 0) {
681	                if (int == 0) return vm.main;
682	                int -= 1;
683	            }
684	
685	            if (vm.worker) |worker| {
686	                if (int >= worker.argv.len) return "";
687	                return this.base.interpreter.getVmArgsUtf8(worker.argv, int);
688	            }
689	            const argv = vm.argv;
690	            if (int >= argv.len) return "";
691	            return argv[int];
692	        },
693	        .mini => {
694	            const ctx = this.base.interpreter.command_ctx;
695	            if (int >= 1 + ctx.passthrough.len) return "";
696	            if (int == 0) return ctx.positionals[ctx.positionals.len - 1 - int];
697	            return ctx.passthrough[int - 1];
698	        },
699	    }
700	}
