709	/// Returns the size of the atom when expanded.
710	/// If the calculation cannot be computed trivially (cmd substitution, brace expansion), this value is not accurate and `has_unknown` is set to true
711	fn expansionSizeHint(this: *const Expansion, atom: *const ast.Atom, has_unknown: *bool) usize {
712	    return switch (@as(ast.Atom.Tag, atom.*)) {
713	        .simple => this.expansionSizeHintSimple(&atom.simple, has_unknown),
714	        .compound => {
715	            if (atom.compound.brace_expansion_hint) {
716	                has_unknown.* = true;
717	            }
718	
719	            var out: usize = 0;
720	            for (atom.compound.atoms) |*simple| {
721	                out += this.expansionSizeHintSimple(simple, has_unknown);
722	            }
723	            return out;
724	        },
725	    };
726	}
727	
728	fn expansionSizeHintSimple(this: *const Expansion, simple: *const ast.SimpleAtom, has_unknown: *bool) usize {
729	    return switch (simple.*) {
730	        .Text => |txt| txt.len,
731	        .quoted_empty => 0,
732	        .Var => |label| this.expandVar(label).len,
733	        .VarArgv => |int| this.expandVarArgv(int).len,
734	        .brace_begin, .brace_end, .comma, .asterisk => 1,
735	        .double_asterisk => 2,
736	        .cmd_subst => |subst| {
737	            _ = subst; // autofix
738	
739	            // TODO check if the command substitution is comprised entirely of assignments or zero-sized things
740	            // if (@as(ast.CmdOrAssigns.Tag, subst.*) == .assigns) {
741	            //     return 0;
742	            // }
743	            has_unknown.* = true;
744	            return 0;
745	        },
746	        .tilde => {
747	            has_unknown.* = true;
748	            return 0;
749	        },
750	    };
751	}
