765	pub const ShellGlobTask = struct {
766	    const debug = bun.Output.scoped(.ShellGlobTask, .hidden);
767	
768	    task: WorkPoolTask = .{ .callback = &runFromThreadPool },
769	
770	    /// Not owned by this struct
771	    expansion: *Expansion,
772	    /// Not owned by this struct
773	    walker: *GlobWalker,
774	
775	    result: std.array_list.Managed([:0]const u8),
776	    event_loop: jsc.EventLoopHandle,
777	    concurrent_task: jsc.EventLoopTask,
778	    // This is a poll because we want it to enter the uSockets loop
779	    ref: bun.Async.KeepAlive = .{},
780	    err: ?Err = null,
781	    alloc_scope: bun.AllocationScope,
782	
783	    const This = @This();
784	
785	    pub const Err = union(enum) {
786	        syscall: Syscall.Error,
787	        unknown: anyerror,
788	
789	        pub fn toJS(this: Err, globalThis: *JSGlobalObject) JSValue {
790	            return switch (this) {
791	                .syscall => |err| err.toJS(globalThis),
792	                .unknown => |err| jsc.ZigString.fromBytes(@errorName(err)).toJS(globalThis),
793	            };
794	        }
795	    };
796	
797	    pub fn createOnMainThread(walker: *GlobWalker, expansion: *Expansion) *This {
798	        debug("createOnMainThread", .{});
799	        var alloc_scope = bun.AllocationScope.init(bun.default_allocator);
800	        var this = bun.handleOom(alloc_scope.allocator().create(This));
801	        this.* = .{
802	            .alloc_scope = alloc_scope,
803	            .event_loop = expansion.base.eventLoop(),
804	            .concurrent_task = jsc.EventLoopTask.fromEventLoop(expansion.base.eventLoop()),
805	            .walker = walker,
806	            .expansion = expansion,
807	            .result = std.array_list.Managed([:0]const u8).init(this.alloc_scope.allocator()),
808	        };
809	
810	        this.ref.ref(this.event_loop);
811	
812	        return this;
813	    }
814	
815	    pub fn runFromThreadPool(task: *WorkPoolTask) void {
816	        debug("runFromThreadPool", .{});
817	        var this: *This = @fieldParentPtr("task", task);
818	        switch (this.walkImpl()) {
819	            .result => {},
820	            .err => |e| {
821	                this.err = .{ .syscall = e };
822	            },
823	        }
824	        this.onFinish();
825	    }
826	
827	    fn walkImpl(this: *This) Maybe(void) {
828	        debug("walkImpl", .{});
829	
830	        var iter = GlobWalker.Iterator{ .walker = this.walker };
831	        defer iter.deinit();
832	        switch (bun.handleOom(iter.init())) {
833	            .err => |err| return .{ .err = err },
834	            else => {},
835	        }
836	
837	        while (switch (iter.next() catch |e| OOM(e)) {
838	            .err => |err| return .{ .err = err },
839	            .result => |matched_path| matched_path,
840	        }) |path| {
841	            bun.handleOom(this.result.append(path));
842	        }
843	
844	        return .success;
845	    }
